    ssize_t read;

    while ((read = getline(&line, &len, file)) != -1) {
        char **tokens = NULL;
        size_t num_tokens = 0;
        char *token = strtok(line, " \t\n");

        while (token) {
            tokens = realloc(tokens, (num_tokens + 1) * sizeof(char *));
            tokens[num_tokens++] = token;
            token = strtok(NULL, " \t\n");
        }

        if (num_tokens < 2) {
            free(tokens);
            continue;
        }

        double a = atof(tokens[num_tokens - 2]);
        double b = atof(tokens[num_tokens - 1]);
        double avg = (a + b) / 2;

        for (size_t i = 0; i < num_tokens; ++i) {
            printf("%s%s", i ? "," : "", tokens[i]);
        }
        printf(",%.2f\n", avg);

        free(tokens);
    }

    free(line);
    fclose(file);
    return 0;
}
