int gmac_setup_tx_queue(struct gmac_device *dev, int num_desc, int desc_mode) {
    dma_addr_t dma_addr;
    struct tx_descriptor *descs;

    descs = dma_alloc_coherent(dev->dev, num_desc * sizeof(*descs), &dma_addr, GFP_KERNEL);
    if (!descs)
        return -ENOMEM;

    dev->tx_descs = descs;
    dev->tx_dma = dma_addr;
    dev->TxDescCount = num_desc;

    writel(dma_addr, &dev->regs->tx_desc_base);
    writel((desc_mode | TX_DESC_ENABLE), &dev->regs->tx_control);

    return 0;
}
