#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(int argc, char *argv[]) {
    int manpage = 0;
    char *output_file = NULL;
    char *input_file = NULL;

    for (int i = 1; i < argc; ) {
        if (strcmp(argv[i], "--manpage") == 0) {
            manpage = 1;
            i++;
        } else if (strcmp(argv[i], "-cs") == 0) {
            i++;
        } else if (strcmp(argv[i], "-o") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: -o requires an output file\n");
                exit(1);
            }
            output_file = argv[i + 1];
            i += 2;
        } else {
            if (!input_file) {
                input_file = argv[i];
                i++;
            } else {
                fprintf(stderr, "Error: Multiple input files provided\n");
                exit(1);
            }
        }
    }

    if (manpage) {
        printf("--manpage: Display manual\n-cs: Option\n-o: Specify output\n");
        return 0;
    }

    if (!input_file) {
        fprintf(stderr, "Usage: %s [--manpage] [-cs] [-o output_file] input_file\n", argv[0]);
        return 1;
    }

    FILE *input = fopen(input_file, "r");
    if (!input) {
        perror("Error opening input file");
        return 1;
    }

    int count = 0;
    char buffer[1024];
    while (fgets(buffer, sizeof(buffer), input)) count++;
    fclose(input);

    FILE *output = stdout;
    if (output_file) {
        output = fopen(output_file, "w");
        if (!output) {
            perror("Error opening output file");
            return 1;
        }
    }

    fprintf(output, "%d\n", count);
    if (output != stdout) fclose(output);

    return 0;
}
