    strncpy(ctx->config_file, "/etc/app/config.conf", sizeof(ctx->config_file));
    ctx->config_file[sizeof(ctx->config_file) - 1] = '\0';

    strncpy(ctx->log_file, "/var/log/app.log", sizeof(ctx->log_file));
    ctx->log_file[sizeof(ctx->log_file) - 1] = '\0';

    strncpy(ctx->service_root, "/var/lib/app", sizeof(ctx->service_root));
    ctx->service_root[sizeof(ctx->service_root) - 1] = '\0';

    if (net_addr != NULL) {
        strncpy(ctx->network_address, net_addr, sizeof(ctx->network_address));
        ctx->network_address[sizeof(ctx->network_address) - 1] = '\0';
        ctx->network_address_set = true;
    } else {
        ctx->network_address[0] = '\0';
        ctx->network_address_set = false;
    }
}

int main(int argc, char *argv[]) {
    Context ctx;
    const char *net_addr = (argc > 1) ? argv[1] : NULL;
    init_context(&ctx, net_addr);
    return 0;
}
