    DownstreamInfo result = {0, NULL};
    if (!str || *str == '\0') return result;

    char* input = strdup(str);
    char* saveptr1, *token;
    int count = 0;

    token = strtok_r(input, ",", &saveptr1);
    while (token) {
        count++;
        token = strtok_r(NULL, ",", &saveptr1);
    }
    free(input);

    if (!count) return result;
    result.hosts = malloc(count * sizeof(DownstreamHost));
    if (!result.hosts) return result;
    result.count = count;

    input = strdup(str);
    token = strtok_r(input, ",", &saveptr1);
    for (int i = 0; token && i < count; i++) {
        char* saveptr2;
        char* host = strtok_r(token, ":", &saveptr2);
        char* data = strtok_r(NULL, ":", &saveptr2);
        char* health = strtok_r(NULL, ":", &saveptr2);

        result.hosts[i].hostname = strdup(host);
        result.hosts[i].data_port = atoi(data);
