ComplexMatrix* create_complex_matrix(int rows, int cols) {
    ComplexMatrix *matrix = malloc(sizeof(ComplexMatrix));
    if (!matrix) return NULL;

    size_t elem_size = sizeof(complex_t);
    size_t row_bytes = cols * elem_size;
    size_t aligned_row_bytes = (row_bytes + 63) / 64 * 64;
    int stride = aligned_row_bytes / elem_size;

    matrix->data = aligned_alloc(64, rows * aligned_row_bytes);
    if (!matrix->data) {
        free(matrix);
        return NULL;
    }

    matrix->rows = rows;
    matrix->cols = cols;
    matrix->stride = stride;
    return matrix;
}

