typedef struct Thread Thread;

typedef struct Scheduler {
    int num_threads;
    Thread* threads;
    int* suspension_thresholds;
    void (*assign_cpu)(Thread*, int);
    pthread_mutex_t mutex;
} Scheduler;

Scheduler* initialize_scheduler(int num_threads, void (*assign_cpu)(Thread*, int)) {
    Scheduler* scheduler = malloc(sizeof(Scheduler));
    if (!scheduler) return NULL;

    scheduler->num_threads = num_threads;

    scheduler->threads = malloc(num_threads * sizeof(Thread));
    if (!scheduler->threads) {
        free(scheduler);
        return NULL;
    }

    scheduler->suspension_thresholds = malloc(num_threads * sizeof(int));
    if (!scheduler->suspension_thresholds) {
        free(scheduler->threads);
        free(scheduler);
        return NULL;
    }

    for (int i = 0; i < num_threads; i++) {
        scheduler->suspension_thresholds[i] = 0;
    }

    for (int i = 0; i < num_threads; i++) {
        assign_cpu(&scheduler->threads[i], i);
    }

    if (pthread_mutex_init(&scheduler->mutex, NULL) != 0) {
        free(scheduler->suspension_thresholds);
        free(scheduler->threads);
        free(scheduler);
        return NULL;
    }

    return scheduler;
}
