#include <ctype.h>

struct Server {
    char *hostname;
    int port;
};

struct Server* parse_servers(const char* str) {
    char *input = strdup(str);
    if (!input) return NULL;

    struct Server *servers = NULL;
    size_t count = 0;

    char *token = strtok(input, ",");
    while (token) {
        char *start = token;
        while (isspace(*start)) start++;
        char *end = start + strlen(start) - 1;
        while (end > start && isspace(*end)) end--;
        *(end + 1) = '\0';

        char *colon = strchr(start, ':');
        if (!colon) {
            free(input);
            for (size_t i = 0; i < count; ++i) free(servers[i].hostname);
            free(servers);
            return NULL;
        }

        *colon = '\0';
        char *host = start;
        int port = atoi(colon + 1);
        char *hostname = strdup(host);
        if (!hostname) {
            free(input);
            for (size_t i = 0; i < count; ++i) free(servers[i].hostname);
            free(servers);
            return NULL;
        }

        struct Server *temp = realloc(servers, (count + 1) * sizeof(struct Server));
        if (!temp) {
            free(hostname);
            free(input);
            for (size_t i = 0; i < count; ++i) free(servers[i].hostname);
            free(servers);
            return NULL;
        }
        servers = temp;

        servers[count].hostname = hostname;
        servers[count].port = port;
        count++;

        token = strtok(NULL, ",");
    }

    free(input);
    return servers;
}
