cl_command_queue createCommandQueue(cl_context context, cl_device_id device_id) {
    cl_int err;
    size_t device_list_size;

    err = clGetContextInfo(context, CL_CONTEXT_DEVICES, 0, NULL, &device_list_size);
    if (err != CL_SUCCESS) return NULL;

    cl_uint num_devices = device_list_size / sizeof(cl_device_id);
    if (num_devices == 0) return NULL;

    cl_device_id *devices = (cl_device_id*)malloc(device_list_size);
    if (!devices) return NULL;

    err = clGetContextInfo(context, CL_CONTEXT_DEVICES, device_list_size, devices, NULL);
    if (err != CL_SUCCESS) {
        free(devices);
        return NULL;
    }

    cl_bool found = CL_FALSE;
    for (cl_uint i = 0; i < num_devices; ++i) {
        if (devices[i] == device_id) {
            found = CL_TRUE;
            break;
        }
    }
    free(devices);

    if (!found) return NULL;

    cl_command_queue cmd_queue;
    cmd_queue = clCreateCommandQueue(context, device_id, 0, &err);
    if (err != CL_SUCCESS) return NULL;

    return cmd_queue;
}
