char* generate_shared_secret(const char* input_str, time_t timestamp, int entropy) {
    char ts_str[32];
    snprintf(ts_str, sizeof(ts_str), "%lld", (long long)timestamp);
    char entropy_str[16];
    snprintf(entropy_str, sizeof(entropy_str), "%d", entropy);

    size_t len_input = strlen(input_str);
    size_t len_ts = strlen(ts_str);
    size_t len_ent = strlen(entropy_str);
    size_t total_len = len_input + len_ts + len_ent;

    char *combined = malloc(total_len + 1);
    if (!combined) return NULL;

    memcpy(combined, input_str, len_input);
    memcpy(combined + len_input, ts_str, len_ts);
    memcpy(combined + len_input + len_ts, entropy_str, len_ent);
    combined[total_len] = '\0';

    unsigned char md5_digest[MD5_DIGEST_LENGTH];
    MD5_CTX ctx;
    MD5_Init(&ctx);
    MD5_Update(&ctx, combined, total_len);
    MD5_Final(md5_digest, &ctx);

    free(combined);

    char *hex_str = malloc(33);
    if (!hex_str) return NULL;

    for (int i = 0; i < MD5_DIGEST_LENGTH; i++) {
        sprintf(hex_str + 2 * i, "%02x", md5_digest[i]);
    }
    hex_str[32] = '\0';

    return hex_str;
}

