#include <stdlib.h>
#include <sys/select.h>
#include <unistd.h>

char *read_line_select(void) {
    size_t size = 128, index = 0;
    char *buffer = malloc(size);
    if (!buffer) return NULL;
    while (1) {
        fd_set fds;
        FD_ZERO(&fds);
        FD_SET(STDIN_FILENO, &fds);
        if (select(STDIN_FILENO + 1, &fds, NULL, NULL, NULL) == -1) {
            free(buffer);
            return NULL;
        }
        if (FD_ISSET(STDIN_FILENO, &fds)) {
            char ch;
            ssize_t n = read(STDIN_FILENO, &ch, 1);
            if (n <= 0) {
                if (index == 0) { free(buffer); return NULL; }
                buffer[index] = '\0';
                return buffer;
            }
            if (ch == '\n') {
                buffer[index] = '\0';
                return buffer;
            }
            if (index + 1 >= size) {
                size *= 2;
                char *new_buf = realloc(buffer, size);
                if (!new_buf) { free(buffer); return NULL; }
                buffer = new_buf;
            }
            buffer[index++] = ch;
        }
    }
}
