char* parse_time(const char* str) {
    static char time[9];
    int len = strlen(str);

    for (int i = 0; i <= len - 8; i++) {
        if (str[i+2] != ':' || str[i+5] != ':') continue;

        if (isdigit(str[i]) && isdigit(str[i+1]) && 
            isdigit(str[i+3]) && isdigit(str[i+4]) &&
            isdigit(str[i+6]) && isdigit(str[i+7])) {

            int hours = (str[i] - '0') * 10 + (str[i+1] - '0');
            int mins = (str[i+3] - '0') * 10 + (str[i+4] - '0');
            int secs = (str[i+6] - '0') * 10 + (str[i+7] - '0');

            if (hours >= 0 && hours <= 23 && mins >= 0 && mins <= 59 && secs >= 0 && secs <= 59) {
                memcpy(time, &str[i], 8);
                time[8] = '\0';
                return time;
            }
        }
    }
    return NULL;
}
