    gtk_widget_set_sensitive(combo, !active);
}

int main(int argc, char **argv) {
    gtk_init(&argc, &argv);

    GtkWidget *window = gtk_window_new(GTK_WINDOW_TOPLEVEL);
    gtk_window_set_title(GTK_WINDOW(window), "Speed Selector");
    gtk_window_set_default_size(GTK_WINDOW(window), 300, 150);

    GtkWidget *box = gtk_box_new(GTK_ORIENTATION_VERTICAL, 5);
    gtk_container_add(GTK_CONTAINER(window), box);

    GtkWidget *combo = gtk_combo_box_text_new();
    gtk_combo_box_text_append_text(GTK_COMBO_BOX_TEXT(combo), "50 Mbps");
    gtk_combo_box_text_append_text(GTK_COMBO_BOX_TEXT(combo), "100 Mbps");
    gtk_combo_box_text_append_text(GTK_COMBO_BOX_TEXT(combo), "1 Gbps");
    gtk_combo_box_text_append_text(GTK_COMBO_BOX_TEXT(combo), "10 Gbps");
    gtk_combo_box_set_active(GTK_COMBO_BOX(combo), 0);

    GtkWidget *entry = gtk_entry_new();
    const gchar *initial_speed = gtk_combo_box_text_get_active_text(GTK_COMBO_BOX_TEXT(combo));
    gtk_entry_set_text(GTK_ENTRY(entry), initial_speed);

    GtkWidget *checkbutton = gtk_check_button_new_with_label("Disable Speed Selection");

    g_signal_connect(combo, "changed", G_CALLBACK(on_combo_changed), entry);
    g_signal_connect(checkbutton, "toggled", G_CALLBACK(on_checkbutton_toggled), combo);
    g_signal_connect(window, "destroy", G_CALLBACK(gtk_main_quit), NULL);

    gtk_box_pack_start(GTK_BOX(box), combo, FALSE, FALSE, 0);
    gtk_box_pack_start(GTK_BOX(box), entry, FALSE, FALSE, 0);
    gtk_box_pack_start(GTK_BOX(box), checkbutton, FALSE, FALSE, 0);

    gtk_widget_show_all(window);

    gtk_main();

    return 0;
}

