typedef struct {
    void* ptr;
    size_t size;
} CustomAllocator;

void init_allocator(CustomAllocator* allocator) {
    allocator->ptr = NULL;
    allocator->size = 0;
}

int custom_alloc(CustomAllocator* allocator, size_t size) {
    if (allocator->ptr) free(allocator->ptr);
    allocator->ptr = malloc(size);
    if (!allocator->ptr) return -1;
    allocator->size = size;
    return 0;
}

void custom_free(CustomAllocator* allocator) {
    free(allocator->ptr);
    allocator->ptr = NULL;
    allocator->size = 0;
}

int custom_realloc(CustomAllocator* allocator, size_t new_size) {
    void* new_ptr = realloc(allocator->ptr, new_size);
    if (!new_ptr) return -1;
    allocator->ptr = new_ptr;
    allocator->size = new_size;
    return 0;
}
