#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_ATHLETES 100

typedef struct {
    char codice[10];
    char name[50];
    char sport[50];
    int hours;
} Athlete;

void searchAthlete(Athlete athletes[], int numAthletes);
void addAthlete(Athlete athletes[], int *numAthletes);
void updateHours(Athlete athletes[], int numAthletes);

int main() {
    Athlete athletes[MAX_ATHLETES];
    int numAthletes = 0;
    int choice;
    char buffer[10];

    do {
        printf("\nMenu:\n1. Search athlete\n2. Add athlete\n3. Update hours\n4. Exit\nEnter choice: ");
        fgets(buffer, sizeof(buffer), stdin);
        sscanf(buffer, "%d", &choice);

        switch(choice) {
            case 1:
                searchAthlete(athletes, numAthletes);
                break;
            case 2:
                addAthlete(athletes, &numAthletes);
                break;
            case 3:
                updateHours(athletes, numAthletes);
                break;
            case 4:
                break;
            default:
                printf("Invalid choice.\n");
        }
    } while (choice != 4);

    return 0;
}

void searchAthlete(Athlete athletes[], int numAthletes) {
    char codice[10];
    printf("Enter codice: ");
    fgets(codice, sizeof(codice), stdin);
    codice[strcspn(codice, "\n")] = '\0';

    for (int i = 0; i < numAthletes; i++) {
        if (strcmp(athletes[i].codice, codice) == 0) {
            printf("Code: %s\nName: %s\nSport: %s\nHours: %d\n", athletes[i].codice, athletes[i].name, athletes[i].sport, athletes[i].hours);
            return;
        }
    }
    printf("Athlete not found.\n");
}

void addAthlete(Athlete athletes[], int *numAthletes) {
    if (*numAthletes >= MAX_ATHLETES) {
        printf("Database full.\n");
        return;
    }

    Athlete a;
    printf("Enter codice: ");
    fgets(a.codice, sizeof(a.codice), stdin);
    a.codice[strcspn(a.codice, "\n")] = '\0';

    for (int i = 0; i < *numAthletes; i++) {
        if (strcmp(athletes[i].codice, a.codice) == 0) {
            printf("Athlete exists.\n");
            return;
        }
    }

    printf("Enter name: ");
    fgets(a.name, sizeof(a.name), stdin);
    a.name[strcspn(a.name, "\n")] = '\0';

    printf("Enter sport: ");
    fgets(a.sport, sizeof(a.sport), stdin);
    a.sport[strcspn(a.sport, "\n")] = '\0';

    char hoursInput[10];
    printf("Enter hours: ");
    fgets(hoursInput, sizeof(hoursInput), stdin);
    sscanf(hoursInput, "%d", &a.hours);

    athletes[*numAthletes] = a;
    (*numAthletes)++;
    printf("Athlete added.\n");
}

void updateHours(Athlete athletes[], int numAthletes) {
    char codice[10];
    printf("Enter codice: ");
    fgets(codice, sizeof(codice), stdin);
    codice[strcspn(codice, "\n")] = '\0';

    for (int i = 0; i < numAthletes; i++) {
        if (strcmp(athletes[i].codice, codice) == 0) {
            char hoursInput[10];
            printf("Enter new hours: ");
            fgets(hoursInput, sizeof(hoursInput), stdin);
            sscanf(hoursInput, "%d", &athletes[i].hours);
            printf("Hours updated.\n");
            return;
        }
    }
    printf("Athlete not found.\n");
}
