EVP_CIPHER_CTX* init_aes_cipher(const char* password) {
    EVP_CIPHER_CTX* ctx = EVP_CIPHER_CTX_new();
    const EVP_CIPHER* cipher = EVP_aes_256_cbc();
    unsigned char key[32], iv[16];

    unsigned char digest[SHA_DIGEST_LENGTH];
    SHA1((const unsigned char*)password, strlen(password), digest);

    memcpy(key, digest, 20);
    memcpy(key + 20, digest, 12);
    memcpy(iv, digest + 12, 4);
    memset(iv + 4, 0, 12);

    EVP_EncryptInit_ex(ctx, cipher, NULL, key, iv);
    return ctx;
}

void cleanup_cipher(EVP_CIPHER_CTX* ctx) {
    EVP_CIPHER_CTX_free(ctx);
