int count_matching_files(const char *pattern) {
    char *dir_path = strdup(pattern);
    char *file_path = strdup(pattern);
    if (!dir_path || !file_path) {
        free(dir_path);
        free(file_path);
        return -1;
    }
    const char *dir = dirname(dir_path);
    const char *file_pat = basename(file_path);
    DIR *dirp = opendir(dir);
    if (!dirp) {
        free(dir_path);
        free(file_path);
        return 0;
    }
    struct dirent *entry;
    int count = 0;
    while ((entry = readdir(dirp)) != NULL) {
        if (fnmatch(file_pat, entry->d_name, 0) == 0) {
            count++;
        }
    }
    closedir(dirp);
    free(dir_path);
    free(file_path);
    return count;
}
