static PyObject* extract_along_axis(PyObject* self, PyObject* args) {
    PyArrayObject *arr;
    int axis;

    if (!PyArg_ParseTuple(args, "O!i", &PyArray_Type, &arr, &axis)) {
        return NULL;
    }

    int ndim = PyArray_NDIM(arr);
    if (axis < 0 || axis >= ndim) {
        PyErr_SetString(PyExc_IndexError, "Axis out of bounds");
        return NULL;
    }

    npy_intp *dims = PyArray_DIMS(arr);
    int new_ndim = ndim - 1;
    npy_intp *new_dims = malloc(new_ndim * sizeof(npy_intp));
    if (!new_dims) {
        PyErr_NoMemory();
        return NULL;
    }

    for (int i = 0, j = 0; i < ndim; i++) {
        if (i != axis) {
            new_dims[j++] = dims[i];
        }
    }

    PyArray_Descr *descr = PyArray_DESCR(arr);
    Py_INCREF(descr);
    PyArrayObject *new_arr = (PyArrayObject*)PyArray_NewFromDescr(
        &PyArray_Type, descr, new_ndim, new_dims, NULL, PyArray_DATA(arr),
        PyArray_FLAGS(arr), NULL);
    free(new_dims);

    if (!new_arr) {
        return NULL;
    }

    Py_INCREF(arr);
    PyArray_SetBaseObject((PyArrayObject*)new_arr, (PyObject*)arr);

    return (PyObject*)new_arr;
}
