int file_contains(const char *path, const char *str) {
    FILE *f = fopen(path, "r");
    if (!f) return 0;

    int found = 0;
    char *buf = NULL;
    long len;

    fseek(f, 0, SEEK_END);
    len = ftell(f);
    fseek(f, 0, SEEK_SET);

    buf = malloc(len + 1);
    if (buf && fread(buf, 1, len, f) == len) {
        buf[len] = 0;
        found = strstr(buf, str) != NULL;
    }

    free(buf);
    fclose(f);
    return found;
}

int traverse(const char *dir, const char *target) {
    DIR *dp = opendir(dir);
    if (!dp) return 0;

    struct dirent *ent;
    int count = 0;

    while ((ent = readdir(dp))) {
        if (!strcmp(ent->d_name, ".") || !strcmp(ent->d_name, ".."))
            continue;

        char path[PATH_MAX];
        snprintf(path, sizeof(path), "%s/%s", dir, ent->d_name);

        struct stat st;
        if (lstat(path, &st) == -1) continue;

        if (S_ISDIR(st.st_mode)) {
            count += traverse(path, target);
        } else if (S_ISREG(st.st_mode) && file_contains(path, target)) {
            count++;
        }
    }

    closedir(dp);
    return count;
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <dir> <string>\n", argv[0]);
        return 1;
    }
    printf("%d\n", traverse(argv[1], argv[2]));
    return 0;
}

