        return 1;
    }

    int num_frames = atoi(argv[opt_idx]);
    const char *filename = argv[opt_idx + 1];

    if (num_frames <= 0) {
        fprintf(stderr, "Invalid number of frames\n");
        return 1;
    }

    FILE *file = fopen(filename, "w");
    if (!file) {
        perror("File open failed");
        return 1;
    }

    for (int i = 0; i < num_frames; i++) {
        char frame[20];
        int len = sprintf(frame, "%d\n", i);
        fwrite(frame, 1, len, file);

        if (show_progress) {
            int progress = (i + 1) * 100 / num_frames;
            printf("\rProgress: %3d%%", progress);
            fflush(stdout);
        }
    }

    fclose(file);

    if (show_progress) {
        printf("\n");
    }

    if (print_count) {
        printf("Frames generated: %d\n", num_frames);
    }

