static int hex_char_to_value(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'A' && c <= 'F') return 10 + c - 'A';
    if (c >= 'a' && c <= 'f') return 10 + c - 'a';
    return 0;
}

static void url_decode(char *str) {
    char *src = str, *dst = str;
    while (*src) {
        if (*src == '%' && isxdigit(src[1]) && isxdigit(src[2])) {
            *dst = (hex_char_to_value(src[1]) << 4) | hex_char_to_value(src[2]);
            dst++;
            src += 3;
        } else if (*src == '+') {
            *dst = ' ';
            dst++;
            src++;
        } else {
            *dst++ = *src++;
        }
    }
    *dst = '\0';
}

void process_form_input(void) {
    char *query = getenv("QUERY_STRING");
    if (!query) return;

    char *buffer = strdup(query);
    if (!buffer) return;

    char *param = strtok(buffer, "&");
    while (param) {
        char *eq = strchr(param, '=');
        if (eq) {
            *eq = '\0';
            char *key = param;
            char *value = eq + 1;
            url_decode(value);
            if (strcmp(key, "message") == 0) {
                char *message = strdup(value);
                if (message) {
                    xQueueSend(oled_queue, &message, portMAX_DELAY);
                }
                break;
            }
        }
        param = strtok(NULL, "&");
    }
    free(buffer);
}
