int main(int argc, char *argv[]) {
    if (argc != 4) {
        fprintf(stderr, "Usage: %s input output rules\n", argv[0]);
        return 1;
    }

    FILE *in = fopen(argv[1], "rb");
    if (!in) {
        perror("Failed to open input file");
        return 1;
    }

    fseek(in, 0, SEEK_END);
    long size = ftell(in);
    fseek(in, 0, SEEK_SET);

    unsigned char *buffer = malloc(size);
    if (!buffer) {
        perror("Memory allocation failed");
        fclose(in);
        return 1;
    }

    if (fread(buffer, 1, size, in) != size) {
        perror("Failed to read input file");
        free(buffer);
        fclose(in);
        return 1;
    }
    fclose(in);

    char *rules = argv[3];
    size_t rules_len = strlen(rules);

    for (long i = 0; i < size; i++) {
        buffer[i] ^= rules[i % rules_len];
    }

    FILE *out = fopen(argv[2], "wb");
    if (!out) {
        perror("Failed to open output file");
        free(buffer);
        return 1;
    }

    if (fwrite(buffer, 1, size, out) != size) {
        perror("Failed to write output file");
        free(buffer);
        fclose(out);
        return 1;
    }

    free(buffer);
    fclose(out);
    return 0;
}
