typedef struct Blob {
    int x;
    int y;
    int lifetime;
    struct Blob* next;
} Blob;

Blob* updateBlobs(Blob* head, int grid_width, int grid_height, int max_lifetime) {
    Blob *current = head, *prev = NULL, *next;

    while (current) {
        next = current->next;
        current->lifetime--;

        if (current->lifetime <= 0) {
            if (prev) prev->next = next;
            else head = next;
            free(current);
        } else prev = current;

        current = next;
    }

    Blob* new_blob = malloc(sizeof(Blob));
    if (new_blob) {
        new_blob->x = rand() % grid_width;
        new_blob->y = rand() % grid_height;
        new_blob->lifetime = (rand() % max_lifetime) + 1;
        new_blob->next = head;
        head = new_blob;
    }

    return head;
}
