char* padded_integer(const char* input) {
    int is_negative = input[0] == '-';
    const char* digits = is_negative ? input + 1 : input;
    int digits_len = strlen(digits);
    int input_len = strlen(input);
    int output_len;

    if (input_len == 1) output_len = 4;
    else if (input_len == 2) output_len = 5;
    else if (input_len == 3) output_len = 6;
    else output_len = input_len;

    int output_digits_len = output_len - (is_negative ? 1 : 0);
    int leading_zeros = output_digits_len - digits_len;
    if (leading_zeros < 0) leading_zeros = 0;

    char* result = malloc(output_len + 1);
    if (!result) return NULL;

    int pos = 0;
    if (is_negative) result[pos++] = '-';
    for (int i = 0; i < leading_zeros; ++i) result[pos++] = '0';
    strcpy(result + pos, digits);
    result[output_len] = '\0';

    return result;
}
