    g->numVertices = 0;
    for (int i = 0; i < MAX_VERTICES; i++) {
        for (int j = 0; j < MAX_VERTICES; j++) {
            g->adjMatrix[i][j] = 0;
        }
    }
}

void displayGraph(Graph *g) {
    printf("\nAdjacency Matrix:\n");
    for (int i = 0; i < g->numVertices; i++) {
        for (int j = 0; j < g->numVertices; j++) {
            printf("%d ", g->adjMatrix[i][j]);
        }
        printf("\n");
    }
}

void modifyVertex(Graph *g) {
    int v;
    printf("Enter vertex to modify (0-%d): ", g->numVertices - 1);
    scanf("%d", &v);

    printf("Enter new edges for vertex %d:\n", v);
    for (int j = 0; j < g->numVertices; j++) {
        printf("Edge from %d to %d? (1/0): ", v, j);
        scanf("%d", &g->adjMatrix[v][j]);
    }
}

void insertVertex(Graph *g) {
    if (g->numVertices >= MAX_VERTICES) {
        printf("Maximum vertices reached!\n");
        return;
    }

    printf("Inserting new vertex %d\n", g->numVertices);
    for (int i = 0; i < g->numVertices; i++) {
        int edge;
        printf("Edge from new vertex %d to %d? (1/0): ", g->numVertices, i);
        scanf("%d", &edge);
        g->adjMatrix[g->numVertices][i] = edge;

        printf("Edge from %d to new vertex %d? (1/0): ", i, g->numVertices);
        scanf("%d", &edge);
        g->adjMatrix[i][g->numVertices] = edge;
    }
    g->numVertices++;
}

void createGraph(Graph *g) {
    int n;
    printf("Enter number of vertices: ");
    scanf("%d", &n);

    g->numVertices = n;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            printf("Edge from %d to %d? (1/0): ", i, j);
            scanf("%d", &g->adjMatrix[i][j]);
        }
    }
}

