    if (strcmp(mode, "read") != 0 && strcmp(mode, "write") != 0) return -1;

    int sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock < 0) return -2;

    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(8080);
    if (inet_pton(AF_INET, ip_address, &server_addr.sin_addr) <= 0) {
        close(sock);
        return -3;
    }

    if (connect(sock, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        close(sock);
        return -3;
    }

    char request[1024];
    snprintf(request, sizeof(request), "%s|%s", filename, mode);
    if (send(sock, request, strlen(request) + 1, 0) < 0) {
        close(sock);
        return -4;
    }

    int server_status;
    if (recv(sock, &server_status, sizeof(server_status), MSG_WAITALL) != sizeof(server_status)) {
        close(sock);
        return -5;
    }
    server_status = ntohl(server_status);
    if (server_status != 0) {
        close(sock);
        return -6;
    }

    if (strcmp(mode, "read") == 0) {
        FILE *file = fopen(filename, "wb");
        if (!file) {
            close(sock);
            return -7;
        }
        char buffer[4096];
        int bytes_read;
        while ((bytes_read = recv(sock, buffer, sizeof(buffer), 0)) > 0) {
            if (fwrite(buffer, 1, bytes_read, file) != bytes_read) {
                fclose(file);
                close(sock);
                return -8;
            }
        }
        fclose(file);
        close(sock);
        if (bytes_read < 0) return -5;
    } else {
        FILE *file = fopen(filename, "rb");
        if (!file) {
            close(sock);
            return -7;
        }
        char buffer[4096];
        size_t bytes_read;
        while ((bytes_read = fread(buffer, 1, sizeof(buffer), file)) > 0) {
            if (send(sock, buffer, bytes_read, 0) != bytes_read) {
                fclose(file);
                close(sock);
                return -4;
            }
        }
        fclose(file);
        close(sock);
        if (ferror(file)) return -8;
    }

    return 0;
}
