        blocks[i].block = malloc(size);
        if (!blocks[i].block) {
            for (int j = 0; j < i; ++j) {
                free(blocks[j].block);
            }
            free(blocks);
            *total_memory = 0;
            *num_structures = 0;
            return NULL;
        }
        *total_memory += size;
    }
    return blocks;
}
