int read_path_table(int fd, uint32_t lba, uint32_t size) {
    char *buf = sysmalloc(size);
    if (!buf) return -1;
    lseek(fd, (off_t)lba * 2048, SEEK_SET);
    read(fd, buf, size);
    size_t pos = 0;
    int count = 0;
    while (pos < size) {
        if (pos + 8 > size) break;
        uint8_t len_di = buf[pos];
        size_t record_size = 8 + len_di + (len_di % 2);
        if (pos + record_size > size) break;
        count++;
        pos += record_size;
    }
    sysfree(buf);
    return count;
}
