bool verify_oauth2_token(const char *json_str) {
    json_error_t error;
    json_t *root = json_loads(json_str, 0, &error);
    if (!root) return false;

    json_t *access_token = json_object_get(root, "access_token");
    json_t *token_type = json_object_get(root, "token_type");
    json_t *expires_in = json_object_get(root, "expires_in");
    bool valid = true;

    if (!access_token || !json_is_string(access_token)) valid = false;
    if (!token_type || !json_is_string(token_type)) valid = false;
    if (!expires_in || !json_is_integer(expires_in)) valid = false;

    if (valid && strcmp(json_string_value(token_type), "Bearer") != 0) valid = false;
    if (valid && json_integer_value(expires_in) <= 0) valid = false;

    json_t *refresh_token = json_object_get(root, "refresh_token");
    if (refresh_token && !json_is_string(refresh_token)) valid = false;

    json_decref(root);
    return valid;
}
