    int type;
} SubStruct;

typedef struct MainStruct {
    SubStruct* sub;
    uint8_t* buffer;
} MainStruct;

int process_struct(const MainStruct* data) {
    uint32_t extracted_value;
    int result = 0;

    switch (data->sub->type) {
        case 0x01:
            memcpy(&extracted_value, data->buffer + 2, sizeof(uint16_t));
            result = (extracted_value & 0xF0) >> 4;
            break;
        case 0x02:
            memcpy(&extracted_value, data->buffer, sizeof(uint32_t));
            result = (extracted_value << 8) | ((extracted_value >> 16) & 0xFF);
            break;
        case 0x03:
            memcpy(&extracted_value, data->buffer + 1, sizeof(uint8_t));
            result = extracted_value ^ 0xAA;
            break;
        default:
            result = -1;
    }

    return result;
}
