int exponential_backoff_with_jitter(MQTTContext *ctx) {
    int retry = 0;
    int max_retries = 5;
    int base_delay = 100;
    int max_delay = 10000;
    int current_backoff = base_delay;

    while (retry < max_retries) {
        if (mqtt_connect(ctx) == 0) {
            return 0;
        }

        int jitter = rand() % current_backoff;
        int delay = current_backoff + jitter;
        delay = delay > max_delay ? max_delay : delay;

        usleep(delay * 1000);

        current_backoff *= 2;
        current_backoff = current_backoff > max_delay ? max_delay : current_backoff;

        retry++;
    }

    return -1;
}
