void des_encrypt(unsigned char key[3], unsigned char *plaintext, unsigned char result[3][8]) {
    DES_cblock des_key = {0};
    for(int i = 0; i < 8; i++) des_key[i] = i < 3 ? key[i] : 0;
    DES_key_schedule schedule;
    DES_set_key_unchecked(&des_key, &schedule);

    for(int i = 0; i < 3; i++) {
        DES_cblock in, out;
        memcpy(in, plaintext + i*8, 8);
        DES_ecb_encrypt(&in, &out, &schedule, DES_ENCRYPT);
        memcpy(result[i], out, 8);
    }
}
