#include <stdlib.h>
#include <string.h>

unsigned char* compute_hash(const unsigned char* input, size_t len, const char* algorithm) {
    unsigned char* hash = NULL;

    if (strcmp(algorithm, "MD2") == 0) {
        hash = malloc(MD2_DIGEST_LENGTH);
        if (hash) MD2(input, len, hash);
    } else if (strcmp(algorithm, "MD4") == 0) {
        hash = malloc(MD4_DIGEST_LENGTH);
        if (hash) MD4(input, len, hash);
    } else if (strcmp(algorithm, "MD5") == 0) {
        hash = malloc(MD5_DIGEST_LENGTH);
        if (hash) MD5(input, len, hash);
    } else if (strcmp(algorithm, "SHA") == 0) {
        hash = malloc(SHA_DIGEST_LENGTH);
        if (hash) SHA1(input, len, hash);
    }

    return hash;
}

